package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.mockito.Mockito.mock;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testValidate() {
        CSVFormat csvFormat = new CSVFormat(',', '"', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);

        assertThrows(IllegalArgumentException.class, csvFormat::validate);

        csvFormat = new CSVFormat(',', ',', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);

        assertThrows(IllegalArgumentException.class, csvFormat::validate);

        csvFormat = new CSVFormat(',', '"', '"', null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);

        assertThrows(IllegalArgumentException.class, csvFormat::validate);

        csvFormat = new CSVFormat(',', '"', null, '"', null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);

        assertThrows(IllegalArgumentException.class, csvFormat::validate);

        csvFormat = new CSVFormat(',', '"', null, null, '"', false, true, "\r\n",
                null, null, null, false, false, false, false, false);

        assertThrows(IllegalArgumentException.class, csvFormat::validate);

        csvFormat = new CSVFormat(',', '"', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);
        csvFormat.withQuoteMode(QuoteMode.NONE);

        assertThrows(IllegalArgumentException.class, csvFormat::validate);

        csvFormat = new CSVFormat(',', '"', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);
        csvFormat.withHeader("A", "B", "A");

        assertThrows(IllegalArgumentException.class, csvFormat::validate);
    }
}
